// Santi AEO — loads the analyzer from your live site and runs it.
const CORE_URL = 'https://santi.co.za/api/aeo-core.js';

const src = await this.helpers.httpRequest({ url: CORE_URL, json: false });
const mod = { exports: {} };
(new Function('module', 'exports', src))(mod, mod.exports);
const core = mod.exports;

const httpGet = async (u) => {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: u,
    headers: { 'User-Agent': 'SantiAEO-Bot/1.0 (+https://santi.co.za/aeo)' },
    timeout: 9000,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    json: false,
  });
  const body = typeof res.body === 'string' ? res.body : (res.body == null ? '' : JSON.stringify(res.body));
  return { status: res.statusCode, body, finalUrl: u };
};

const j = ($input.first() && $input.first().json) || {};
let url =
  (j.query && j.query.url) ||
  (j.body && j.body.url) ||
  (j.params && j.params.url) ||
  (typeof j.url === 'string' ? j.url : null);

if (!url) {
  return [{ json: { error: 'No URL received by the AEO webhook.', _debugKeys: Object.keys(j), _query: j.query || null } }];
}

try {
  const report = await core.analyze(String(url).trim(), httpGet);
  return [{ json: report }];
} catch (e) {
  return [{ json: { error: (e && e.message) || 'Something went wrong.', _gotUrl: String(url) } }];
}
